def get_application_property(
    *,
    key: str | None = None,
    permissionLevel: str | None = None,
    keyFilter: str | None = None,
    client: Client | None = None,
    **kwargs: Any,
) -> list[ApplicationProperty] | ErrorCollection | ErrorCollection:
    """
    Returns all application properties or an application property.

    If you specify a value for the `key` parameter, then an application property is returned as an object (not in an array). Otherwise, an array of all editable application properties is returned. See [Set application property](#api-rest-api-3-application-properties-id-put) for descriptions of editable properties.

    **[Permissions](#permissions) required:** *Administer Jira* [global permission](https://confluence.atlassian.com/x/x4dKLg).
    """
    c = client or Client()
    response = c._request(
        method='get',
        path='/rest/api/3/application-properties',
        params={'key': key, 'permissionLevel': permissionLevel, 'keyFilter': keyFilter},
        **kwargs,
    )
    return c._parse_response(
        response, list[ApplicationProperty] | ErrorCollection | ErrorCollection
    )


