def get_dashboards_paginated(
    *,
    dashboardName: str | None = None,
    accountId: str | None = None,
    owner: str | None = None,
    groupname: str | None = None,
    groupId: str | None = None,
    projectId: int | None = None,
    orderBy: AutoEnum5 | None = None,
    startAt: int | None = None,
    maxResults: int | None = None,
    status: AutoEnum6 | None = None,
    expand: str | None = None,
    client: Client | None = None,
    **kwargs: Any,
) -> PageBeanDashboard | ErrorCollection | ErrorCollection:
    """
    Returns a [paginated](#pagination) list of dashboards. This operation is similar to [Get dashboards](#api-rest-api-3-dashboard-get) except that the results can be refined to include dashboards that have specific attributes. For example, dashboards with a particular name. When multiple attributes are specified only filters matching all attributes are returned.

    This operation can be accessed anonymously.

    **[Permissions](#permissions) required:** The following dashboards that match the query parameters are returned:

     *  Dashboards owned by the user. Not returned for anonymous users.
     *  Dashboards shared with a group that the user is a member of. Not returned for anonymous users.
     *  Dashboards shared with a private project that the user can browse. Not returned for anonymous users.
     *  Dashboards shared with a public project.
     *  Dashboards shared with the public.
    """
    c = client or Client()
    response = c._request(
        method='get',
        path='/rest/api/3/dashboard/search',
        params={
            'dashboardName': dashboardName,
            'accountId': accountId,
            'owner': owner,
            'groupname': groupname,
            'groupId': groupId,
            'projectId': projectId,
            'orderBy': orderBy,
            'startAt': startAt,
            'maxResults': maxResults,
            'status': status,
            'expand': expand,
        },
        **kwargs,
    )
    return c._parse_response(
        response, PageBeanDashboard | ErrorCollection | ErrorCollection
    )


