def add_issue_types_to_context(
    fieldId: str,
    contextId: int,
    body: IssueTypeIds,
    *,
    client: Client | None = None,
    **kwargs: Any,
) -> dict[str, Any]:
    """
    Adds issue types to a custom field context, appending the issue types to the issue types list.

    A custom field context without any issue types applies to all issue types. Adding issue types to such a custom field context would result in it applying to only the listed issue types.

    If any of the issue types exists in the custom field context, the operation fails and no issue types are added.

    This API will not allow adding issue types to the global context from April 2026. Instead, an HTTP 400 response will be returned. See [CHANGE-3019](https://developer.atlassian.com/changelog/#CHANGE-3019)

    **[Permissions](#permissions) required:** *Administer Jira* [global permission](https://confluence.atlassian.com/x/x4dKLg).
    """
    c = client or Client()
    response = c._request(
        method='put',
        path=f'/rest/api/3/field/{fieldId}/context/{contextId}/issuetype',
        json=body.model_dump(),
        **kwargs,
    )
    return c._parse_response(response, dict[str, Any])


