def remove_custom_field_context_from_projects(
    fieldId: str,
    contextId: int,
    body: ProjectIds,
    *,
    client: Client | None = None,
    **kwargs: Any,
) -> dict[str, Any]:
    """
    Removes a custom field context from projects.

    A custom field context without any projects applies to all projects. Removing all projects from a custom field context would result in it applying to all projects.

    If any project in the request is not assigned to the context, or the operation would result in two global contexts for the field, the operation fails.

    **[Permissions](#permissions) required:** *Administer Jira* [global permission](https://confluence.atlassian.com/x/x4dKLg).
    """
    c = client or Client()
    response = c._request(
        method='post',
        path=f'/rest/api/3/field/{fieldId}/context/{contextId}/project/remove',
        json=body.model_dump(),
        **kwargs,
    )
    return c._parse_response(response, dict[str, Any])


