    c = client or Client()
    return c._request(
        method='delete',
        path=f'/rest/api/3/issue/{issueIdOrKey}/worklog',
        params={
            'adjustEstimate': adjustEstimate,
            'overrideEditableFlag': overrideEditableFlag,
        },
        json=body.model_dump(),
        **kwargs,
    )


