def get_field_auto_complete_for_query_string(
    *,
    fieldName: str | None = None,
    fieldValue: str | None = None,
    predicateName: str | None = None,
    predicateValue: str | None = None,
    client: Client | None = None,
    **kwargs: Any,
) -> AutoCompleteSuggestions:
    """
    Returns the JQL search auto complete suggestions for a field.

    Suggestions can be obtained by providing:

     *  `fieldName` to get a list of all values for the field.
     *  `fieldName` and `fieldValue` to get a list of values containing the text in `fieldValue`.
     *  `fieldName` and `predicateName` to get a list of all predicate values for the field.
     *  `fieldName`, `predicateName`, and `predicateValue` to get a list of predicate values containing the text in `predicateValue`.

    This operation can be accessed anonymously.

    **[Permissions](#permissions) required:** None.
    """
    c = client or Client()
    response = c._request(
        method='get',
        path='/rest/api/3/jql/autocompletedata/suggestions',
        params={
            'fieldName': fieldName,
            'fieldValue': fieldValue,
            'predicateName': predicateName,
            'predicateValue': predicateValue,
        },
        **kwargs,
    )
    return c._parse_response(response, AutoCompleteSuggestions)


