def match_issues(
    body: IssuesAndJQLQueries, *, client: Client | None = None, **kwargs: Any
) -> IssueMatches:
    """
    Checks whether one or more issues would be returned by one or more JQL queries.

    **[Permissions](#permissions) required:** None, however, issues are only matched against JQL queries where the user has:

     *  *Browse projects* [project permission](https://confluence.atlassian.com/x/yodKLg) for the project that the issue is in.
     *  If [issue-level security](https://confluence.atlassian.com/x/J4lKLg) is configured, issue-level security permission to view the issue.
    """
    c = client or Client()
    response = c._request(
        method='post', path='/rest/api/3/jql/match', json=body.model_dump(), **kwargs
    )
    return c._parse_response(response, IssueMatches)


