def delete_project_asynchronously(
    projectIdOrKey: str, *, client: Client | None = None, **kwargs: Any
) -> TaskProgressBeanObject:
    """
    Deletes a project asynchronously.

    This operation is:

     *  transactional, that is, if part of the delete fails the project is not deleted.
     *  [asynchronous](#async). Follow the `location` link in the response to determine the status of the task and use [Get task](#api-rest-api-3-task-taskId-get) to obtain subsequent updates.

    **[Permissions](#permissions) required:** *Administer Jira* [global permission](https://confluence.atlassian.com/x/x4dKLg).
    """
    c = client or Client()
    response = c._request(
        method='post', path=f'/rest/api/3/project/{projectIdOrKey}/delete', **kwargs
    )
    return c._parse_response(response, TaskProgressBeanObject)


