def create_user(
    body: NewUserDetails, *, client: Client | None = None, **kwargs: Any
) -> User:
    """
    Creates a user. This resource is retained for legacy compatibility. As soon as a more suitable alternative is available this resource will be deprecated.

    **Note:** This API does not support Forge apps.

    If the user exists and has access to Jira, the operation returns a 201 status. If the user exists but does not have access to Jira, the operation returns a 400 status.

    **[Permissions](#permissions) required:** *Administer Jira* [global permission](https://confluence.atlassian.com/x/x4dKLg). The caller has to be an **organization admin**.
    """
    c = client or Client()
    response = c._request(
        method='post', path='/rest/api/3/user', json=body.model_dump(), **kwargs
    )
    return c._parse_response(response, User)


