def get_failed_webhooks(
    *,
    maxResults: int | None = None,
    after: int | None = None,
    client: Client | None = None,
    **kwargs: Any,
) -> FailedWebhooks | ErrorCollection | ErrorCollection:
    """
    Returns webhooks that have recently failed to be delivered to the requesting app after the maximum number of retries.

    After 72 hours the failure may no longer be returned by this operation.

    The oldest failure is returned first.

    This method uses a cursor-based pagination. To request the next page use the failure time of the last webhook on the list as the `failedAfter` value or use the URL provided in `next`.

    **[Permissions](#permissions) required:** Only [Connect apps](https://developer.atlassian.com/cloud/jira/platform/index/#connect-apps) can use this operation.
    """
    c = client or Client()
    response = c._request(
        method='get',
        path='/rest/api/3/webhook/failed',
        params={'maxResults': maxResults, 'after': after},
        **kwargs,
    )
    return c._parse_response(
        response, FailedWebhooks | ErrorCollection | ErrorCollection
    )


